    browser_ver, os_ver, terminal, connect_url,
    refer_url, session_id
) VALUES (
    GETDATE(), #{sysId}, #{visitIp}, #{browser}, #{os},
    #{browserVer}, #{osVer}, #{terminal}, #{connectUrl},
    #{referUrl}, #{sessionId}
)

mapper.sql:
SELECT access_seq, user_id, user_nm, connect_type, org_code, org_nm, public_ip, private_ip, connect_dt, connect_action, connect_url, browser, os, session_id FROM TB_USER_ACCESS_LOG WHERE 1=1
AND user_id LIKE CONCAT('%', #{userId}, '%')
AND connect_dt >= #{beginDt}
AND connect_dt <= #{endDt}

mapper.select:
SELECT PL.* FROM (
    SELECT PO.*, ROW_NUMBER() OVER(ORDER BY connect_dt DESC) AS rsn
    FROM (  ) PO
) PL
WHERE rsn > #{minSn} AND rsn <= #{maxSn}

