SELECT CAST(visit_dt AS DATE) AS visit_date, COUNT(*) AS visit_cnt, COUNT(DISTINCT visit_ip) AS unique_ip_cnt, COUNT(DISTINCT session_id) AS session_cnt FROM TB_VISIT_STATS_LOG WHERE 1=1
AND visit_dt >= #{beginDt}
AND visit_dt <= #{endDt}
AND sys_id = #{sysId}
GROUP BY CAST(visit_dt AS DATE) ORDER BY visit_date DESC

SELECT M.menu_id, M.menu_nm, COUNT(*) AS access_cnt, CAST(MS.menu_dt AS DATE) AS access_date FROM TB_MENU_STATS_LOG MS LEFT JOIN TB_MENU_INFO M ON MS.menu_id = M.menu_id WHERE 1=1
AND MS.menu_dt >= #{beginDt}
AND MS.menu_dt <= #{endDt}
AND MS.sys_id = #{sysId}
GROUP BY M.menu_id, M.menu_nm, CAST(MS.menu_dt AS DATE) ORDER BY access_cnt DESC
